sql:
SELECT site_id, AVG(water_level) AS avg_water_level
FROM water_levels
GROUP BY site_id;

SELECT COUNT(*) as site_count
FROM sites
WHERE site_type = 'river';

external_knowledge:
- 'investigators' and 'data analysts' refer to 'researcher' and 'data analyst' roles respectively;
- 'recent cautionary notices' are synonymous with 'alert' type reports;
- 'this month' refers to the current month in the context of the query execution.

sql:
SELECT flow_rate, measurement_date
FROM flow_rates
WHERE site_id = 1;

SELECT *
FROM sites
ORDER BY site_name ASC;

SELECT measurement_date, water_level
FROM water_levels
ORDER BY measurement_date DESC;

external_knowledge:
- Notably murky refers to a turbidity level above 5.0;
- Quite high water depth is defined as water levels above 15.0;
- Murkiness from worst to least means ordering by turbidity value in descending order.

sql:
SELECT site_name 
FROM sites 
WHERE site_id IN (
  SELECT site_id 
  FROM water_levels
) 
AND site_id NOT IN (
  SELECT site_id 
  FROM flow_rates
);

SELECT * 
FROM sites 
INNER JOIN water_levels ON sites.site_id = water_levels.site_id;

SELECT MIN(water_level) AS lowest_water_level, MAX(water_level) AS highest_water_level
FROM water_levels
WHERE site_id = 1;
